<div class="page-title"><h2>Movimientos y ajustes de inventario</h2></div><div class="grid two"><div class="card"><h3>Filtros</h3><form method="get" action="/inventory/movements" class="form inline-form"><label>Desde<input type="date" name="from" value="<?= e($from) ?>"></label><label>Hasta<input type="date" name="to" value="<?= e($to) ?>"></label><button class="btn">Filtrar</button></form></div><div class="card"><h3>Ajuste de inventario</h3><form method="post" action="/inventory/adjust" class="form two-cols"><?= csrf_field() ?><label>ID producto<input type="number" name="product_id" required></label><label>ID almacén<input type="number" name="warehouse_id" required></label><label>Cantidad (+/-)<input type="number" step="0.01" name="quantity" required></label><label class="col-span-2">Notas<textarea name="notes"></textarea></label><button class="btn col-span-2">Aplicar ajuste</button></form></div></div><div class="card"><table class="table"><thead><tr><th>Fecha</th><th>Producto</th><th>Almacén</th><th>Tipo</th><th>Cantidad</th><th>Referencia</th><th>Notas</th></tr></thead><tbody><?php foreach($movements as $row): ?><tr><td><?= e($row['created_at']) ?></td><td><?= e(product_display_name($row['product_name'] ?? '', $row['category_name'] ?? '')) ?></td><td><?= e($row['warehouse_name']) ?></td><td><?= e($row['movement_type']) ?></td><td><?= money($row['quantity']) ?></td><td><?= e($row['reference']) ?></td><td><?= e($row['notes']) ?></td></tr><?php endforeach; ?></tbody></table></div>
